  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 26, 'אני מלווה תהליכי בניית קשרים עם עיתונות ודוברים חיצוניים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 27, 'אני מחזק את היכולת לנסח מסרים מקצועיים וברורים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 28, 'אני מסייע בפיתוח קמפיינים דיגיטליים ומשולבים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 29, 'אני מלווה תהליכי הדרכה והכשרה בדוברות ותקשורת.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 30, 'אני מחזק את היכולת לנתח מגמות תקשורת ולהגיב להן.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 31, 'אני מסייע ביצירת תוכן שמחזק את הערכים של הארגון.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 32, 'אני מלווה תהליכי ניהול תקשורת פנימית בארגונים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 33, 'אני מחזק את היכולת להשתמש בכלי מדיה בצורה מקצועית.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 34, 'אני מסייע ביצירת חיזוק יחסי ציבור עם קהלים מגוונים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 35, 'אני מלווה תהליכי ייעוץ אסטרטגי למנהלים ודוברים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 36, 'אני מחזק את היכולת להתמודד עם פרסומים שליליים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 37, 'אני מסייע בפיתוח מערכות יחסים עם מובילי דעת קהל.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 38, 'אני מלווה תהליכי הפקת אירועים תקשורתיים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 39, 'אני מחזק את היכולת ליישם אסטרטגיות תקשורת מותאמות לארגון.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 40, 'אני מסייע ביצירת תוכן ויזואלי וטקסטואלי איכותי.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 41, 'אני מלווה תהליכי הפקת חומרי הדרכה ומצגות.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 42, 'אני מחזק את היכולת ליצור שיח גלוי, שקוף ואמין.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 43, 'אני מסייע בניהול פרויקטים תקשורתיים מורכבים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 44, 'אני מלווה תהליכי עבודה מול כלי תקשורת ומדיה.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 45, 'אני מחזק את היכולת לפתח סדנאות והדרכות תקשורתיות.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 46, 'אני מסייע ביצירת מסרים שמחברים בין אנשים וארגונים.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 47, 'אני מלווה תהליכי יצירת תוכן שיווקי חכם ואפקטיבי.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 48, 'אני מחזק את היכולת לנהל משברים עם מקצועיות ורוגע.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 49, 'אני מסייע ביצירת תוכניות תקשורת חינוכיות ומניעות שינוי.'),
  (35, 'דוברות ויחסי ציבור', 'דוברות, ניהול משברים, ייעוץ תקשורתי', 50, 'אני מלווה תהליכי ייעוץ והכוונה מקצועית בתחום הדוברות והיח"צ.')
